487	The following two file-internal helpers in the \texttt{GenericFreeness} namespace package
488	the finite \(A\)-module leaf in the two forms (flatness and module-finiteness) that the
489	chain and the geometric globalization consume. Both are already proved axiom-clean.
490	
491	\begin{lemma}
492	
493	\leanok
494	[Flat localization away, finite module]
495	  \label{lem:gf_flat_finite}
496	  \lean{AlgebraicGeometry.GenericFreeness.exists_flat_localizationAway_of_finite}
497	  \uses{lem:gf_finite_module}
498	  Let \(A\) be a noetherian domain and \(M\) a finite \(A\)-module. Then there exists
499	  \(f \in A\), \(f \ne 0\), such that \texttt{LocalizedModule (Submonoid.powers f) M} is
500	  \emph{flat} over \texttt{Localization.Away f}.
501	\end{lemma}
502	\begin{proof}
503	  \uses{lem:gf_finite_module}
504	  \leanok
505	  By \cref{lem:gf_finite_module} the localized module is free over
506	  \texttt{Localization.Away f}; free modules are flat (\texttt{Module.Flat.of\_free}).
507	\end{proof}

509	\begin{lemma}
510	
511	\leanok
512	[Free localization away, module-finite variant]
513	  \label{lem:gf_free_moduleFinite}
514	  \lean{AlgebraicGeometry.GenericFreeness.exists_free_localizationAway_of_moduleFinite}
515	  \uses{lem:gf_finite_module}
516	  Let \(A\) be a noetherian domain, \(B\) a module-finite \(A\)-algebra
517	  (\texttt{[Module.Finite A B]}), and \(M\) a finite \(B\)-module
518	  (\texttt{[Module.Finite B M]}) with the compatible \(A\)-module structure via the
519	  scalar tower \(A \to B \to M\). Then there exists \(f \in A\), \(f \ne 0\), such
520	  that \texttt{LocalizedModule (Submonoid.powers f) M} is free over
521	  \texttt{Localization.Away f}.
522	\end{lemma}
523	\begin{proof}
524	  \uses{lem:gf_finite_module}
525	  The \(A\)-finiteness of \(M\) is \emph{derived}, not assumed: since \(B\) is
526	  module-finite over \(A\) and \(M\) is module-finite over \(B\), composition along
527	  the scalar tower \(A \to B \to M\) makes \(M\) module-finite over \(A\) (transitivity
528	  of module-finiteness, \texttt{Module.Finite.trans}~\(B~M\)). With \(M\) now a finite
529	  \(A\)-module, \cref{lem:gf_finite_module} produces the required \(f \ne 0\) with
530	  \texttt{LocalizedModule (Submonoid.powers} f) M\) free over
531	  \texttt{Localization.Away} f\). The lemma is therefore strictly more general than a
532	  repackaging of \cref{lem:gf_finite_module}: the finite \(A\)-algebra \(B\) and the
533	  finite \(B\)-module \(M\) are the genuine inputs, and \(A\)-finiteness is a
534	  consequence of the hypotheses rather than one of them.
535	\end{proof}
